// Function to extract image GUIDs from HTML
function extractImageGuids(htmlContent) {
    const regex = /media\/pictures\/([a-f0-9-]{36})/g;
    const matches = htmlContent.match(regex);
    
    if (!matches) return [];
    
    // Extract unique GUIDs
    const guids = [...new Set(matches.map(match => match.split('/')[2]))];
    return guids;
}

// Function to download a single image
async function downloadImage(guid, index, total) {
    const imgUrl = `https://media.staticontent.com/media/pictures/${guid}`;
    const ext = '.jpeg'; // Default extension
    const filename = `${String(index).padStart(3, '0')} - ${baseName}${ext}`;
    const filePath = path.join(__dirname, outputDir, filename);
    
    return new Promise((resolve, reject) => {
        console.log(`Downloading (${index}/${total}): ${guid}`);
        
        const file = fs.createWriteStream(filePath);
        const request = https.get(imgUrl, (response) => {
            if (response.statusCode === 200) {
                response.pipe(file);
                
                file.on('finish', () => {
                    file.close();
                    console.log(`✔ Saved: ${filename}`);
                    resolve();
                });
            } else {
                file.close();
                try {
                    fs.unlinkSync(filePath);
                } catch (e) {
                    // File might not exist
                }
                console.warn(`⚠ Failed (${response.statusCode}): ${guid}`);
                resolve(); // Resolve anyway to continue with others
            }
        }).on('error', (err) => {
            try {
                fs.unlinkSync(filePath);
            } catch (e) {
                // File might not exist
            }
            console.warn(`⚠ Error: ${guid} - ${err.message}`);
            resolve(); // Resolve anyway to continue with others
        });
        
        request.setTimeout(30000, () => {
            request.destroy();
            console.warn(`⚠ Timeout: ${guid}`);
            resolve();
        });
    });
}

// Main function
async function downloadAllImages() {
    try {
        // Create directory for downloaded images
        if (!fs.existsSync(outputDir)) {
            fs.mkdirSync(outputDir);
        }
        
        // Extract GUIDs
        const guids = extractImageGuids(htmlContent);
        
        if (guids.length === 0) {
            console.log('No image GUIDs found in the HTML content.');
            return;
        }
        
        console.log(`Found ${guids.length} unique images to download.\n`);
        
        // Download images sequentially to maintain order
        let downloadedCount = 0;
        for (let i = 0; i < guids.length; i++) {
            await downloadImage(guids[i], i + 1, guids.length);
            downloadedCount++;
            
            // Small delay to be respectful to the server
            if (i < guids.length - 1) {
                await new Promise(resolve => setTimeout(resolve, 500));
            }
        }
        
        console.log(`\n✅ Finished downloading ${downloadedCount} full-size images`);
        
    } catch (error) {
        console.error('Error:', error.message);
    }
}

// Run the script
downloadAllImages();